        try {
          const fileContent = fs.readFileSync(dbPath, 'utf-8');
          const lines = fileContent.trim().split('\n').filter(l => l.length > 0);

          // All 3 keys should have been written
          const rows = lines.map(l => JSON.parse(l));
          const keys = rows.map(r => r.key);

